class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int satisfiedCustomers = 0;
        int grumpyCount = 0;
        int satisfiedGrumpyCount = 0;

        for (int i = 0; i < minutes; i++) {
            if (grumpy[i] == 0) {
                satisfiedCustomers += customers[i];
            } else {
                grumpyCount++;
                satisfiedGrumpyCount++;
            }
        }

        if (grumpyCount == 0) {
            return satisfiedCustomers;
        } else if (grumpyCount == minutes) {
            return satisfiedCustomers + satisfiedGrumpyCount;
        } else {
            return 0;
        }
    }
}
